from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triples about food into a single fluent sentence.
    """
    if not triples:
        return ""

    # Helper to turn a single triple into a phrase
    def triple_to_phrase(t: Triple) -> str:
        s, p, o = t.subject, t.predicate, t.object
        # Expanded natural language mappings for all supported predicates
        if p == "country":
            return f"{s} is from {o}"
        if p == "ingredient":
            return f"{s} contains {o}"
        if p == "region":
            return f"{s} originates from {o}"
        if p == "division":
            return f"{s} belongs to the division {o}"
        if p == "family":
            return f"{s} is in the family {o}"
        if p == "order":
            return f"{s} is classified under the order {o}"
        if p == "class":
            return f"{s} belongs to the class {o}"
        if p == "genus":
            return f"{s} belongs to the genus {o}"
        if p == "course":
            return f"{s} is served as a {o}"
        if p == "capital":
            return f"The capital of {s} is {o}"
        if p == "leader":
            return f"The leader of {s} is {o}"
        if p == "leaderTitle":
            return f"The title of the leader of {s} is {o}"
        if p == "alternativeName":
            return f"{s} is also known as {o}"
        if p == "creator":
            return f"{s} was created by {o}"
        if p == "creatorOfDish":
            return f"{s} was created by {o}"
        if p == "mainIngredient":
            return f"The main ingredients of {s} are {o}"
        if p == "dishVariation":
            return f"{s} can vary with {o}"
        if p == "servingTemperature" or p == "served":
            return f"{s} is served {o}"
        if p == "year":
            return f"{s} was introduced in {o}"
        if p == "carbohydrate":
            return f"{s} contains {o} of carbohydrates"
        if p == "fat":
            return f"{s} contains {o} of fat"
        if p == "protein":
            return f"{s} contains {o} of protein"
        if p == "servingSize":
            return f"The serving size of {s} is {o}"
        if p == "related":
            return f"{s} is related to {o}"
        if p == "similarDish":
            return f"{s} is similar to {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p == "currency":
            return f"The currency of {s} is {o}"
        if p == "demonym":
            return f"The demonym for {s} is {o}"
        if p == "language":
            return f"The language spoken in {s} is {o}"
        if p == "officialLanguage":
            return f"The official language of {s} is {o}"
        if p == "ethnicGroup":
            return f"The ethnic group of {s} is {o}"
        if p == "foundationPlace":
            return f"{s} was founded in {o}"
        # Default generic phrasing for any unspecified predicate
        return f"{s} {p} {o}"

    # Build more fluent sentence by grouping predicates per subject
    from collections import defaultdict

    subject_map = defaultdict(list)
    for t in triples:
        subject_map[t.subject].append(t)

    subject_clauses = []
    for subj, tlist in subject_map.items():
        # Convert each predicate/object pair to a short phrase
        parts = []
        for idx, t in enumerate(tlist):
            phrase = triple_to_phrase(t)
            # Normalise phrase by removing trailing punctuation
            phrase = phrase.rstrip('.')
            # Determine if the phrase already contains the subject context
            lower_phrase = phrase.lower()
            has_subject = (
                lower_phrase.startswith(subj.lower() + " ")
                or f"{subj.lower()}'s" in lower_phrase
                or lower_phrase.startswith(f"the {t.predicate} of {subj.lower()}")
            )
            # For the first predicate we keep the full phrase (it usually introduces the subject)
            # For subsequent predicates we drop a leading subject reference if present
            if idx > 0 and has_subject:
                # Remove the subject part up to the first space after it
                if lower_phrase.startswith(subj.lower() + " "):
                    phrase = phrase[len(subj) + 1 :].lstrip()
                elif f"{subj.lower()}'s" in lower_phrase:
                    # replace possessive form with empty string
                    phrase = phrase.replace(f"{subj}'s ", "").replace(f"{subj}'s", "")
                elif lower_phrase.startswith(f"the {t.predicate} of {subj.lower()}"):
                    # replace the leading pattern with a simpler form
                    phrase = phrase[len(f"The {t.predicate} of {subj}") :].lstrip()
            parts.append(phrase)

        # Build the clause for this subject
        if not parts:
            continue
        if len(parts) == 1:
            clause = parts[0]
        else:
            # Build a more natural clause: first part introduces the subject,
            # subsequent parts are linked with “which” and the final part with “and”.
            first, *middle, last = parts
            # Prefix middle parts with “which”
            middle_phrases = [f"which {p}" for p in middle]
            # Join middle parts with commas
            middle_joined = ", ".join(middle_phrases)
            # Assemble the clause
            clause = f"{first}"
            if middle_joined:
                clause += f", {middle_joined}"
            clause += f", and {last}"
        subject_clauses.append(clause)

    # Combine subject clauses into final sentence
    if len(subject_clauses) == 1:
        sentence = subject_clauses[0]
    else:
        sentence = ", ".join(subject_clauses[:-1]) + ", and " + subject_clauses[-1]

    # Ensure final punctuation
    if not sentence.endswith('.'):
        sentence += '.'
    return sentence

# EVOLVE-BLOCK-END
